#include <stdio.h>

void reverse(int *start, int *end) {
    while (start < end) {
        int tmp = *start;
        *start = *end;
        *end = tmp;
        ++start;
        --end;
    }
}

void rotate(int *arr, int n, long long k) {
    if (n == 0) return;
    k %= n;
    if (k == 0) return;
    reverse(arr, arr + n - 1);
    reverse(arr, arr + k - 1);
    reverse(arr + k, arr + n - 1);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        long long K;
        scanf("%d %lld", &N, &K);
        int arr[100000];
        for (int i = 0; i < N; ++i) {
            scanf("%d", &arr[i]);
        }
        rotate(arr, N, K);
        for (int i = 0; i < N; ++i) {
            printf("%d", arr[i]);
            if (i + 1 == N) printf("\n");
            else printf(" ");
        }
    }
    return 0;
}

