#include <bits/stdc++.h>
using namespace std;

void reverseRange(vector<int>& a, int l, int r) {
    while (l < r) {
        swap(a[l], a[r]);
        ++l; --r;
    }
}

void rotate(vector<int>& a, long long k) {
    int n = a.size();
    if (n == 0) return;
    k %= n;
    if (k == 0) return;
    reverseRange(a, 0, n - 1);
    reverseRange(a, 0, (int)k - 1);
    reverseRange(a, (int)k, n - 1);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int N; long long K;
        cin >> N >> K;
